440: // Filters the nodes to find the ones that fit the pod based on the framework
441: // filter plugins and filter extenders.
442: func (sched *Scheduler) findNodesThatFitPod(ctx context.Context, fwk framework.Framework, state *framework.CycleState, pod *v1.Pod) ([]*framework.NodeInfo, framework.Diagnosis, error) {
443: 	logger := klog.FromContext(ctx)
444: 	diagnosis := framework.Diagnosis{
445: 		NodeToStatusMap: make(framework.NodeToStatusMap),
446: 	}
447: 
448: 	allNodes, err := sched.nodeInfoSnapshot.NodeInfos().List()
449: 	if err != nil {
450: 		return nil, diagnosis, err
451: 	}
452: 	// Run "prefilter" plugins.
453: 	preRes, s := fwk.RunPreFilterPlugins(ctx, state, pod)
454: 	if !s.IsSuccess() {
455: 		if !s.IsRejected() {
456: 			return nil, diagnosis, s.AsError()
457: 		}
458: 		// All nodes in NodeToStatusMap will have the same status so that they can be handled in the preemption.
459: 		// Some non trivial refactoring is needed to avoid this copy.
460: 		for _, n := range allNodes {
461: 			diagnosis.NodeToStatusMap[n.Node().Name] = s
462: 		}
463: 
464: 		// Record the messages from PreFilter in Diagnosis.PreFilterMsg.
465: 		msg := s.Message()
466: 		diagnosis.PreFilterMsg = msg
467: 		logger.V(5).Info("Status after running PreFilter plugins for pod", "pod", klog.KObj(pod), "status", msg)
468: 		diagnosis.AddPluginStatus(s)
469: 		return nil, diagnosis, nil
470: 	}
471: 
472: 	// "NominatedNodeName" can potentially be set in a previous scheduling cycle as a result of preemption.
473: 	// This node is likely the only candidate that will fit the pod, and hence we try it first before iterating over all nodes.
474: 	if len(pod.Status.NominatedNodeName) > 0 {
475: 		feasibleNodes, err := sched.evaluateNominatedNode(ctx, pod, fwk, state, diagnosis)
476: 		if err != nil {
477: 			logger.Error(err, "Evaluation failed on nominated node", "pod", klog.KObj(pod), "node", pod.Status.NominatedNodeName)
478: 		}
479: 		// Nominated node passes all the filters, scheduler is good to assign this node to the pod.
480: 		if len(feasibleNodes) != 0 {
481: 			return feasibleNodes, diagnosis, nil
482: 		}
483: 	}
484: 
485: 	nodes := allNodes
486: 	if !preRes.AllNodes() {
487: 		nodes = make([]*framework.NodeInfo, 0, len(preRes.NodeNames))
488: 		for _, n := range allNodes {
489: 			if !preRes.NodeNames.Has(n.Node().Name) {
490: 				// We consider Nodes that are filtered out by PreFilterResult as rejected via UnschedulableAndUnresolvable.
491: 				// We have to record them in NodeToStatusMap so that they won't be considered as candidates in the preemption.
492: 				diagnosis.NodeToStatusMap[n.Node().Name] = framework.NewStatus(framework.UnschedulableAndUnresolvable, "node is filtered out by the prefilter result")
493: 				continue
494: 			}
495: 			nodes = append(nodes, n)
496: 		}
497: 	}
498: 	feasibleNodes, err := sched.findNodesThatPassFilters(ctx, fwk, state, pod, &diagnosis, nodes)
499: 	// always try to update the sched.nextStartNodeIndex regardless of whether an error has occurred
500: 	// this is helpful to make sure that all the nodes have a chance to be searched
501: 	processedNodes := len(feasibleNodes) + len(diagnosis.NodeToStatusMap)
502: 	sched.nextStartNodeIndex = (sched.nextStartNodeIndex + processedNodes) % len(nodes)
503: 	if err != nil {
504: 		return nil, diagnosis, err
505: 	}
506: 
507: 	feasibleNodesAfterExtender, err := findNodesThatPassExtenders(ctx, sched.Extenders, pod, feasibleNodes, diagnosis.NodeToStatusMap)
508: 	if err != nil {
509: 		return nil, diagnosis, err
510: 	}
511: 	if len(feasibleNodesAfterExtender) != len(feasibleNodes) {
512: 		// Extenders filtered out some nodes.
513: 		//
514: 		// Extender doesn't support any kind of requeueing feature like EnqueueExtensions in the scheduling framework.
515: 		// When Extenders reject some Nodes and the pod ends up being unschedulable,
516: 		// we put framework.ExtenderName to pInfo.UnschedulablePlugins.
517: 		// This Pod will be requeued from unschedulable pod pool to activeQ/backoffQ
518: 		// by any kind of cluster events.
519: 		// https://github.com/kubernetes/kubernetes/issues/122019
520: 		if diagnosis.UnschedulablePlugins == nil {
521: 			diagnosis.UnschedulablePlugins = sets.New[string]()
522: 		}
523: 		diagnosis.UnschedulablePlugins.Insert(framework.ExtenderName)
524: 	}
525: 
526: 	return feasibleNodesAfterExtender, diagnosis, nil
527: }
