596: func nodeSpecUnschedulableChanged(newNode *v1.Node, oldNode *v1.Node) bool {
597: 	return newNode.Spec.Unschedulable != oldNode.Spec.Unschedulable && !newNode.Spec.Unschedulable
598: }
